/* CAN Bus Message Struct - can_driver.h */
#ifndef CAN_DRIVER_H
#define CAN_DRIVER_H

#include <stdint.h>

typedef struct {
    uint32_t id;          /* CAN frame ID */
    uint8_t  dlc;         /* Data Length Code (0-8) */
    uint8_t  data[8];     /* Payload */
    uint8_t  is_extended; /* 1 if extended 29-bit ID */
    uint8_t  is_rtr;      /* 1 if Remote Transmission Request */
} can_frame_t;

int  can_init(uint8_t channel, uint32_t baudrate);
int  can_send(uint8_t channel, const can_frame_t *frame);
int  can_recv(uint8_t channel, can_frame_t *frame, uint32_t timeout_ms);
void can_flush(uint8_t channel);

#endif /* CAN_DRIVER_H */

